/** Bilingual label -- adds English parens for non-en */
export function bt(lang: LangCode, key: string): string {
  const v = T[key];
  if (!v) return key;
  if (lang === "en") return v.en;
  return (v[lang] || v.en) + " (" + v.en + ")";
}

/** Plain translate */
export function t(lang: LangCode, key: string): string {
  const v = T[key];
  if (!v) return key;
  return v[lang] || v.en;
}
